    created_at          TEXT NOT NULL,
    resolved_at         TEXT,
    telegram_message_id INTEGER,
    telegram_chat_id    TEXT NOT NULL DEFAULT '',
    callback_sent       INTEGER NOT NULL DEFAULT 0
);

